#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static bool controller_all_sensors_valid(const controller_t *controller, uint32_t now_ms)
{
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return false;
    }
    if ((now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    if ((now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    return true;
}

static void controller_update_state_and_actuators(controller_t *controller, controller_state_t new_state)
{
    controller->state = new_state;

    switch (new_state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        controller->filter_on = false;
        controller->drain_open = false;
        break;
    case CONTROLLER_STATE_COMPLETE:
        controller->filter_on = false;
        controller->drain_open = false;
        break;
    case CONTROLLER_STATE_FILTERING:
        controller->filter_on = true;
        controller->drain_open = false;
        break;
    case CONTROLLER_STATE_SETTLING:
        controller->filter_on = false;
        controller->drain_open = false;
        break;
    case CONTROLLER_STATE_DRAINING:
        controller->filter_on = false;
        controller->drain_open = true;
        break;
    default:
        controller->filter_on = false;
        controller->drain_open = false;
        break;
    }
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle sensor timeout or invalid input - always go to safe idle */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        return output;
    }

    /* Handle valid turbidity input */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
    }

    /* Handle valid level input */
    if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    /* Check for sensor timeout - both sensors must be fresh */
    bool sensor_timeout = !controller_all_sensors_valid(controller, input.now_ms);

    if (sensor_timeout) {
        controller_set_safe_idle(controller);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        return output;
    }

    /* Handle CONTROLLER_INPUT_NONE - just check timeouts, don't change state */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        /* No new sensor data, but sensors are valid and fresh - stay in current state */
        controller_output_t stale_output = {
            .filter_on = controller->filter_on,
            .drain_open = controller->drain_open,
            .state = controller->state,
            .state_name = controller_state_name(controller->state),
            .changed = false,
            .timed_out = false,
        };
        return stale_output;
    }

    /* Main state machine logic */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Stay in SAFE_IDLE until both sensors have valid data and level >= 40 */
        if (controller->has_valid_turbidity && controller->has_valid_level) {
            if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_update_state_and_actuators(controller, CONTROLLER_STATE_FILTERING);
                } else {
                    /* Level is sufficient but turbidity is already clear - go to settling */
                    controller->settling_started_ms = input.now_ms;
                    controller_update_state_and_actuators(controller, CONTROLLER_STATE_SETTLING);
                }
            } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_update_state_and_actuators(controller, CONTROLLER_STATE_COMPLETE);
            }
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Check for complete level - go to COMPLETE */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller_update_state_and_actuators(controller, CONTROLLER_STATE_COMPLETE);
            break;
        }

        /* Clear streak logic: valid TURB <= 35 increments, > 35 resets */
        if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            controller->clear_streak_count++;

            /* Check if we have enough clear samples and can move to settling */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                controller->settling_started_ms = input.now_ms;
                controller_update_state_and_actuators(controller, CONTROLLER_STATE_SETTLING);
            }
        } else {
            /* Turbidity increased - reset clear streak */
            controller->clear_streak_count = 0;
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        /* Check for complete level - go to COMPLETE */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller_update_state_and_actuators(controller, CONTROLLER_STATE_COMPLETE);
            break;
        }

        /* Check for disturbance during settling: TURB > 40 resets streak and returns to FILTERING */
        if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            controller->clear_streak_count = 0;
            controller_update_state_and_actuators(controller, CONTROLLER_STATE_FILTERING);
            break;
        }

        /* Check if settling time has elapsed (400ms) and conditions are met */
        uint32_t elapsed_settling_ms = input.now_ms - controller->settling_started_ms;
        if (elapsed_settling_ms >= CONTROLLER_SETTLING_MS && 
            controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller_update_state_and_actuators(controller, CONTROLLER_STATE_DRAINING);
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        /* Check for complete level - stay in COMPLETE */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller_update_state_and_actuators(controller, CONTROLLER_STATE_COMPLETE);
            break;
        }

        /* Check for disturbance during draining: TURB > 50 and LEVEL >= 40 */
        if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->clear_streak_count = 0;
            controller_update_state_and_actuators(controller, CONTROLLER_STATE_FILTERING);
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* Stay in COMPLETE until sensor timeout or invalid input */
        if (controller->last_level < CONTROLLER_MIN_PROCESS_LEVEL && 
            controller->last_level >= CONTROLLER_COMPLETE_LEVEL) {
            /* Level is between complete and min - stay in complete */
        } else if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Level recovered above minimum - go back to safe idle */
            controller_update_state_and_actuators(controller, CONTROLLER_STATE_SAFE_IDLE);
        }
        break;

    default:
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

