#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static bool controller_all_sensors_valid(const controller_t *controller, uint32_t now_ms)
{
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return false;
    }
    if ((now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    if ((now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return false;
    }
    return true;
}

static void controller_update_state_and_actuators(controller_t *controller, controller_state_t new_state)
{
    controller->state = new_state;

    switch (new_state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        controller->filter_on = false;
        controller->drain_open = false;
        break;
    case CONTROLLER_STATE_COMPLETE:
        controller->filter_on = false;
        controller->drain_open = false;
        break;
    case CONTROLLER_STATE_FILTERING:
        controller->filter_on = true;
        controller->drain_open = false;
        break;
